    // Use a priority queue (min-heap) to process nodes in order of earliest arrival time
    const pq: [number, number][] = [[0, 0]]; // [time, node]
    const dist: Map<number, number> = new Map(); // Minimum time to reach each node
    dist.set(0, 0);

    while (pq.length > 0) {
        // Extract the node with the earliest arrival time
        const [time, node] = pq.shift!();
        if (node === n - 1) {
            return time;
        }

        // Skip if we have already found a better time to reach this node
